import React, { useState, useEffect, useRef } from "react";
import {
    MapContainer,
    TileLayer,
    Marker,
    useMap,
    useMapEvents
} from "react-leaflet";
import "leaflet/dist/leaflet.css";
import L from "leaflet";
import icon from "leaflet/dist/images/marker-icon.png";
import iconShadow from "leaflet/dist/images/marker-shadow.png";
import { Col, Row } from "reactstrap";
import { Label } from "reactstrap";
import Select from 'react-select';
import Transparentspinner from "../../Common/Loader/Transparentspinner";

let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41],
});
L.Marker.prototype.options.icon = DefaultIcon;

function MapClickHandler({ handleLocationUpdate }) {
    useMapEvents({
        click(e) {
            handleLocationUpdate(e.latlng.lat, e.latlng.lng);
        },
    });
    return null;
}

// --- 2. Component to Fly to Search Result ---
function RecenterMap({ lat, lng }) {
    const map = useMap();
    useEffect(() => {
        if (lat && lng) {
            map.flyTo([lat, lng], 14);
        }
    }, [lat, lng, map]);
    return null;
}

function SetLocation({ Controller, setValue, control, handlemodal,stbData }) {
    const DEFAULT_LAT = stbData?.latitude?stbData?.latitude:10.1632;
    const DEFAULT_LNG = stbData?.longitude?stbData?.longitude:76.6413;

    const [position, setPosition] = useState({ lat: DEFAULT_LAT, lng: DEFAULT_LNG });
    const [displayLocation, setDisplayLocation] = useState({
        lat: stbData?.latitude?stbData?.latitude:'',
        lng: stbData?.longitude?stbData?.longitude:'',
        address: stbData?.location_address?stbData?.location_address:''
    });

    const [loading, setLoading] = useState(false);
    const [placeOption, setPlaceOption] = useState([]);
    const searchTimeout = useRef(null);

    useEffect(() => {
        setPosition({ lat: DEFAULT_LAT, lng: DEFAULT_LNG });
        setDisplayLocation({  lat: stbData?.latitude?stbData?.latitude:'',
        lng: stbData?.longitude?stbData?.longitude:'',
        address: stbData?.location_address?stbData?.location_address:''});
        setPlaceOption([]);
       
    }, []);

    const handleLocationUpdate = async (lat, lng) => {
        setLoading(true);
        setPosition({ lat, lng });
        setDisplayLocation(prev => ({ ...prev, lat, lng, address: "Fetching address..." }));

        try {
            const response = await fetch(
                `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&accept-language=en`,
                { headers: { "User-Agent": "MyReactApp/1.0" } }
            );
            const data = await response.json();

            if (data && data.display_name) {
                const fullAddress = data.display_name;

                setDisplayLocation({ lat, lng, address: fullAddress });

                // Update the Dropdown value via React Hook Form
                setValue('placename', {
                    label: fullAddress,
                    value: data.place_id,
                    lat: lat,
                    lon: lng
                });
            }
        } catch (error) {
            setDisplayLocation(prev => ({ ...prev, address: "Location found (Address unavailable)" }));
        }
        setLoading(false);
    };


    const getCurrentLocation = () => {
        if (!navigator.geolocation) {
            alert("Geolocation is not supported by your browser");
            return;
        }

        setLoading(true);
        navigator.geolocation.getCurrentPosition(
            (position) => {
                const { latitude, longitude } = position.coords;
                handleLocationUpdate(latitude, longitude);
            },
            (error) => {
                alert("Unable to retrieve your location. Check browser permissions.");
                setLoading(false);
            }
        );
    };

    const handleSearch = (inputValue, actionMeta) => {
        if (actionMeta.action !== "input-change") return;
        if (!inputValue) return;

        if (searchTimeout.current) clearTimeout(searchTimeout.current);

        searchTimeout.current = setTimeout(async () => {
            setLoading(true);
            try {
                const response = await fetch(
                    `https://nominatim.openstreetmap.org/search?format=json&q=${inputValue}&accept-language=en`,
                    { headers: { "User-Agent": "MyReactApp/1.0" } }
                );
                const data = await response.json();

                if (data && data.length > 0) {
                    const option = data.map((item) => ({
                        label: item.display_name,
                        value: item.place_id,
                        lat: parseFloat(item.lat),
                        lon: parseFloat(item.lon)
                    }));
                    setPlaceOption(option);
                }
            } catch (error) {
            }
            setLoading(false);
        }, 600);
    };

    const mapTriger = (result) => {
        if (!result?.lat) return;
        setPosition({ lat: result.lat, lng: result.lon });
        setDisplayLocation({
            lat: result.lat,
            lng: result.lon,
            address: result.label
        });
    };

    // --- FIX: Clear data after saving ---
    const handleSave = () => {
        // 1. Save data to parent form
        setValue('lat', displayLocation.lat);
        setValue('log', displayLocation?.lng);
        setValue('address', displayLocation?.address);
        
        // 2. Clear the Search Dropdown (React Select)
        setValue('placename', null); 

        // 3. Reset Local State (Map & Text)
        setPosition({ lat: DEFAULT_LAT, lng: DEFAULT_LNG });
        setDisplayLocation({ lat: '', lng: '', address: '' });
        setPlaceOption([]);

        // 4. Close Modal
        handlemodal();
    }

    return (
        <div className="px-4" >
            {loading && <Transparentspinner />}

            <Row>
                <Col md="4">
                    <div className="mb-3">
                        <Label className="form-label">Search Place</Label>
                        <Controller
                            name="placename"
                            control={control}
                            render={({ field }) => (
                                <Select
                                    {...field}
                                    options={placeOption}
                                    isClearable={true}
                                    placeholder="Type to search..."
                                    // Ensure value is controlled properly
                                    value={field.value} 
                                    onChange={(value) => {
                                        field.onChange(value);
                                        mapTriger(value);
                                    }}
                                    onInputChange={handleSearch}
                                    isLoading={loading}
                                />
                            )}
                        />
                    </div>

                    <div className="my-4 p-3  rounded border">
                        <p className="mb-1"><strong>Latitude:</strong> {displayLocation?.lat||'N/A'}</p>
                        <p className="mb-1"><strong>Longitude:</strong> {displayLocation?.lng||'N/A'}</p>
                        <p className="mb-0"><strong>Place:</strong> {displayLocation?.address||'N/A'}</p>
                    </div>
                    <div className="mb-3 d-grid">
                        <button
                            type="button"
                            onClick={(e) => {
                                e.preventDefault();
                                getCurrentLocation();
                            }}
                            className="btn btn-outline-primary "
                        >
                            Current Location
                        </button>
                    </div>
                </Col>
                <Col md="8">
                    <MapContainer
                        center={position}
                        zoom={13}
                        style={{ height: "350px", width: "100%", borderRadius: "8px" }}
                    >
                        <TileLayer
                            attribution='&copy; OpenStreetMap'
                            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                        />

                        <Marker position={position} />

                        <MapClickHandler handleLocationUpdate={handleLocationUpdate} />

                        <RecenterMap lat={position.lat} lng={position.lng} />
                    </MapContainer>
                </Col>
            </Row>
            <div className="mt-2 d-flex justify-content-end">
                <button type="button" onClick={() => { handleSave() }} className="btn btn-primary">Save Location</button>
            </div>
        </div>
    );
}

export default SetLocation;